#include <bits/stdc++.h>
#define int long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e5+5;
int l[MAXN],r[MAXN],k,p,n,m;
bool d[MAXN];
signed main(void)
{
	n=read();
    r[1]=n+1,l[1]=0;
    FOR(i,2,n)
    {
        k=read(),p=read();
        if(p==0)
        {
            r[l[k]]=i;
            l[i]=l[k];
            l[k]=i;
            r[i]=k;
        }
        else
        {
            l[r[k]]=i;
            r[i]=r[k];
            r[k]=i;
            l[i]=k;
        }
    }
    m=read();
    FOR(i,1,m)
    {
        int x=read();
        if(!d[x])
        {
            d[x]=true;
            l[r[x]]=l[x];
            r[l[x]]=r[x];
        }
    }
    for(int p=r[0];p!=n+1;p=r[p])
    {
        write(p);
        pc(' ');
    }
	return false;
}
